mapper.select:
SELECT sa.id, sa.user_id, up.name AS staff_name, sa.attend_date, sa.check_in, sa.check_out, sa.memo, sa.created_at FROM staff_attendance sa LEFT JOIN user_profiles up ON up.user_id = sa.user_id WHERE sa.attend_date BETWEEN #{startDate} AND #{endDate}
AND sa.user_id = #{userId}
ORDER BY sa.attend_date DESC, sa.check_in ASC
